   310→ */
   311→pmScheduleRoutes.post('/pm/schedule', async (c) => {
   312→  const requestId = getRequestId(c);
   313→  const body = await c.req.json();
   314→
   315→  // Validate required fields
   316→  if (!body.trainId || !isValidUuid(body.trainId)) {
