     1→/**
     2→ * Drift Analysis Routes
     3→ *
     4→ * REST endpoints for drift analysis monitoring.
     5→ * Drift analysis compares actual fleet state against published baselines
     6→ * to detect schedule and mileage deviations requiring attention.
     7→ *
     8→ * @see specs/005-api.md Section 5.9
     9→ */
    10→
    11→import { Hono } from 'hono';
    12→import {
    13→  success,
    14→  paginatedSuccess,
    15→  error,
    16→  parsePaginationQuery,
    17→  ErrorCodes,
    18→  type AppVariables,
    19→} from '../types';
    20→import { getRequestId, getRequestDuration } from '../middleware/request-context';
    21→import {
    22→  getDriftMonitorService,
    23→  getBaselineService,
    24→  type DriftHistoryFilters,
    25→} from '../../services';
    26→import { isValidUuid } from '../../lib/schemas';
    27→
    28→// Singleton service instances
    29→let driftService: ReturnType<typeof getDriftMonitorService> | null = null;
    30→let baselineService: ReturnType<typeof getBaselineService> | null = null;
    31→
    32→function getDriftService(): ReturnType<typeof getDriftMonitorService> {
    33→  if (!driftService) {
    34→    driftService = getDriftMonitorService();
    35→  }
    36→  return driftService;
    37→}
    38→
    39→function getBaseline(): ReturnType<typeof getBaselineService> {
    40→  if (!baselineService) {
    41→    baselineService = getBaselineService();
    42→  }
    43→  return baselineService;
    44→}
    45→
    46→export const driftRoutes = new Hono<{ Variables: AppVariables }>();
    47→
    48→/**
    49→ * Map drift severity based on whether replan is required
    50→ */
    51→function getDriftSeverity(
    52→  mileageDriftPct: number,
    53→  maxPmDriftDays: number,
    54→  requiresReplan: boolean,
    55→  thresholds: { mileageDriftPct: number; scheduleDriftDays: number }
    56→): 'GREEN' | 'YELLOW' | 'RED' {
    57→  if (requiresReplan) {
    58→    return 'RED';
    59→  }
    60→
    61→  // Approaching threshold (>70% of threshold)
    62→  const mileageApproaching = Math.abs(mileageDriftPct) > thresholds.mileageDriftPct * 0.7;
    63→  const scheduleApproaching = maxPmDriftDays > thresholds.scheduleDriftDays * 0.7;
    64→
    65→  if (mileageApproaching || scheduleApproaching) {
    66→    return 'YELLOW';
    67→  }
    68→
    69→  return 'GREEN';
    70→}
    71→
    72→/**
    73→ * GET /drift/analysis
    74→ *
    75→ * Get drift analysis results comparing actual state against baseline.
    76→ * Returns the latest drift analysis with summary and per-train details.
    77→ *
    78→ * Query Parameters:
    79→ * - baselineId: Filter by specific baseline (UUID, optional - defaults to latest published)
    80→ * - trainId: Filter by specific train (UUID, optional)
    81→ * - requiresReplan: Filter trains requiring replan (boolean, optional)
    82→ * - page: Page number for train analyses (default: 1)
    83→ * - pageSize: Items per page (default: 50, max: 200)
    84→ */
    85→driftRoutes.get('/drift/analysis', async (c) => {
    86→  const requestId = getRequestId(c);
    87→  const service = getDriftService();
    88→  const baselines = getBaseline();
    89→
    90→  // Parse query parameters
    91→  const baselineIdParam = c.req.query('baselineId');
    92→  const trainIdParam = c.req.query('trainId');
    93→  const requiresReplanParam = c.req.query('requiresReplan');
    94→
    95→  // Validate UUIDs if provided
    96→  if (baselineIdParam && !isValidUuid(baselineIdParam)) {
    97→    return c.json(
    98→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid baseline ID format', requestId),
    99→      400
   100→    );
   101→  }
   102→
   103→  if (trainIdParam && !isValidUuid(trainIdParam)) {
   104→    return c.json(
   105→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid train ID format', requestId),
   106→      400
   107→    );
   108→  }
   109→
   110→  // Get baseline (specific or latest published)
   111→  let baseline;
   112→  if (baselineIdParam) {
   113→    try {
   114→      baseline = await baselines.getBaselineById(baselineIdParam);
   115→    } catch {
   116→      return c.json(
   117→        error(ErrorCodes.NOT_FOUND, `Baseline not found: ${baselineIdParam}`, requestId),
   118→        404
   119→      );
   120→    }
   121→  } else {
   122→    baseline = await baselines.getLatestBaseline();
   123→    if (!baseline) {
   124→      return c.json(
   125→        error(ErrorCodes.NOT_FOUND, 'No published baseline found', requestId),
   126→        404
   127→      );
   128→    }
   129→  }
   130→
   131→  // Build filters for drift history query
   132→  const filters: DriftHistoryFilters = {
