   143→
   144→  // Parse pagination
   145→  const pagination = parsePaginationQuery({
   146→    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
   147→    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
   148→  });
   149→
   150→  // Get drift summary
