   421→/**
   422→ * GET /scenarios/:id/changes
   423→ *
   424→ * Get all changes (deltas) applied to a scenario in order.
   425→ */
   426→scenarioRoutes.get('/scenarios/:id/changes', async (c) => {
   427→  const requestId = getRequestId(c);
   428→  const scenarioId = c.req.param('id');
   429→
   430→  if (!isValidUuid(scenarioId)) {
   431→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid scenario ID format', requestId), 400);
   432→  }
   433→
   434→  const service = getService();
   435→  const deltas = await service.getScenarioDeltas(scenarioId);
   436→
   437→  const changes = deltas.map((delta) => ({
   438→    id: delta.id,
   439→    sequenceNum: delta.sequenceNum,
   440→    deltaType: delta.deltaType,
   441→    entityType: delta.entityType,
   442→    entityId: delta.entityId,
   443→    oldValues: delta.oldValues,
   444→    newValues: delta.newValues,
   445→    changeReason: delta.changeReason,
   446→    createdBy: delta.createdBy,
   447→    createdAt: delta.createdAt,
   448→  }));
   449→
   450→  return c.json(
   451→    success(changes, { timing: { durationMs: getRequestDuration(c) } })
   452→  );
   453→});
   454→
   455→/**
   456→ * POST /scenarios/:id/undo
   457→ *
   458→ * Undo the last change applied to a scenario.
   459→ */
   460→scenarioRoutes.post('/scenarios/:id/undo', async (c) => {
   461→  const requestId = getRequestId(c);
   462→  const scenarioId = c.req.param('id');
   463→
   464→  if (!isValidUuid(scenarioId)) {
   465→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid scenario ID format', requestId), 400);
   466→  }
   467→
   468→  const userId = c.get('user')?.id ?? 'system';
   469→
   470→  const service = getService();
