   478→/**
   479→ * GET /scenarios/:id/materialized
   480→ *
   481→ * Get the materialized (fully computed) state of a scenario.
   482→ * This applies all deltas to the base state and returns the resulting PM schedule.
   483→ */
   484→scenarioRoutes.get('/scenarios/:id/materialized', async (c) => {
   485→  const requestId = getRequestId(c);
   486→  const scenarioId = c.req.param('id');
   487→
   488→  if (!isValidUuid(scenarioId)) {
   489→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid scenario ID format', requestId), 400);
   490→  }
