   492→  const service = getService();
   493→  const materialized = await service.materializeScenario(scenarioId);
   494→
   495→  return c.json(
   496→    success(
   497→      {
   498→        scenario: materialized.scenario
   499→          ? {
   500→              id: materialized.scenario.id,
   501→              name: materialized.scenario.name,
   502→              status: materialized.scenario.status,
   503→            }
   504→          : null,
   505→        baselineId: materialized.baselineId,
