   511→          trainNumber: pm.trainNumber,
   512→          pmTypeId: pm.pmTypeId,
   513→          pmCode: pm.pmCode,
   514→          targetDate: pm.targetDate,
   515→          assignedTrackId: pm.assignedTrackId,
   516→          assignedHours: pm.assignedHours,
   517→          status: pm.status,
   518→          constraintStart: pm.constraintStart,
   519→          constraintEnd: pm.constraintEnd,
   520→          isLocked: pm.isLocked,
   521→        })),
   522→        pmCount: materialized.pmSchedule.length,
   523→      },
   524→      { timing: { durationMs: getRequestDuration(c) } }
   525→    )
   526→  );
   527→});
