   670→    scenarioId,
   671→    baselineName: body.baselineName.trim(),
   672→    baselineDescription: body.description?.trim(),
   673→    userId,
   674→  });
   675→
   676→  return c.json(
   677→    success(
   678→      {
   679→        promoted: true,
   680→        scenarioId,
   681→        baseline: {
   682→          id: baseline.id,
   683→          name: baseline.name,
   684→          version: baseline.version,
   685→          baselineDate: baseline.baselineDate,
   686→          status: baseline.status,
   687→          publishedAt: baseline.publishedAt,
   688→        },
   689→      },
   690→      { timing: { durationMs: getRequestDuration(c) } }
   691→    ),
   692→    201
   693→  );
   694→});
   695→
   696→/**
   697→ * POST /scenarios/cleanup
   698→ *
   699→ * Manually trigger cleanup of expired scenarios.
   700→ * Normally this runs as a scheduled job.
   701→ */
   702→scenarioRoutes.post('/scenarios/cleanup', async (c) => {
