  1019→/**
  1020→ * GET /canvas/drift-overlay
  1021→ *
  1022→ * Get drift overlay data showing train drift severity relative to baseline.
  1023→ * Used to highlight trains requiring attention in the canvas.
  1024→ *
  1025→ * Query Parameters:
  1026→ * - baselineId: Baseline to compare against (UUID, optional - defaults to latest published)
  1027→ */
  1028→canvasRoutes.get('/canvas/drift-overlay', async (c) => {
  1029→  const requestId = getRequestId(c);
  1030→  
  1031→  const baselineIdParam = c.req.query('baselineId');
  1032→
  1033→  if (baselineIdParam && !isValidUuid(baselineIdParam)) {
  1034→    return c.json(
