  1036→      400
  1037→    );
  1038→  }
  1039→
  1040→  let baseline;
  1041→  if (baselineIdParam) {
  1042→    const result = await db
  1043→      .select()
  1044→      .from(planBaselines)
  1045→      .where(eq(planBaselines.id, baselineIdParam))
  1046→      .limit(1);
  1047→
  1048→    if (result.length === 0) {
  1049→      return c.json(
