  1053→    }
  1054→    baseline = result[0];
  1055→  } else {
  1056→    const result = await db
  1057→      .select()
  1058→      .from(planBaselines)
  1059→      .where(eq(planBaselines.status, 'PUBLISHED'))
  1060→      .orderBy(desc(planBaselines.publishedAt))
  1061→      .limit(1);
  1062→
  1063→    if (result.length === 0) {
