/**
 * Canvas Data Routes
 *
 * REST endpoints for Canvas visualization data.
 * Provides strategic (yearly), tactical (weekly), and overlay data
 * for the scheduling canvas UI component.
 *
 * Canvas Views:
 * - Strategic: Yearly PM aggregates per train for heatmap display
 * - Tactical: Weekly PM blocks with constraint walls for detailed scheduling
 * - Man-hour overlay: Depot workload utilization by week
 * - Drift overlay: Train drift severity relative to baseline
 *
 * @see specs/005-api.md Section 5.13
 */

import { Hono } from 'hono';
import { and, desc, eq, gte, inArray, isNull, lte, sql } from 'drizzle-orm';
import {
  success,
  error,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import { db } from '../../lib/db/connection';
import {
  trains,
  fleets,
  pmSchedule,
  pmTypes,
  tracks,
  depots,
  manhourProjections,
  manhourAdjustments,
  driftAnalysis,
  planBaselines,
} from '../../lib/db/schema';
import { isValidUuid } from '../../lib/schemas';

export const canvasRoutes = new Hono<{ Variables: AppVariables }>();

/**
 * GET /canvas/strategic
 *
 * Get strategic-level canvas data with yearly PM aggregates.
 * Used for the heatmap view showing PM density over multi-year horizons.
 *
 * Query Parameters:
 * - fleetId: Filter by fleet (UUID, optional)
 * - fromYear: Start year (number, defaults to current year)
 * - toYear: End year (number, defaults to current year + 10)
 */
canvasRoutes.get('/canvas/strategic', async (c) => {
  const requestId = getRequestId(c);

  const fleetIdParam = c.req.query('fleetId');
  const fromYearParam = c.req.query('fromYear');
  const toYearParam = c.req.query('toYear');

  if (fleetIdParam && !isValidUuid(fleetIdParam)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid fleet ID format', requestId),
      400
    );
  }

  const currentYear = new Date().getFullYear();
  const fromYear = fromYearParam ? parseInt(fromYearParam, 10) : currentYear;
  const toYear = toYearParam ? parseInt(toYearParam, 10) : currentYear + 10;

  if (isNaN(fromYear) || isNaN(toYear) || fromYear > toYear) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid year range', requestId),
      400
    );
  }

  const fromDate = `${fromYear}-01-01`;
  const toDate = `${toYear}-12-31`;

  const conditions = [
    gte(pmSchedule.targetDate, fromDate),
    lte(pmSchedule.targetDate, toDate),
    isNull(pmSchedule.scenarioId),
  ];

  if (fleetIdParam) {
    conditions.push(eq(trains.fleetId, fleetIdParam));
  }

  const results = await db
    .select({
      trainId: trains.id,
      trainNumber: trains.trainNumber,
      fleetId: trains.fleetId,
      fleetCode: fleets.code,
      year: sql<number>`EXTRACT(YEAR FROM ${pmSchedule.targetDate})::integer`.as('year'),
      pmCount: sql<number>`COUNT(${pmSchedule.id})::integer`.as('pm_count'),
      totalHours: sql<string>`COALESCE(SUM(${pmSchedule.assignedHours}), 0)`.as('total_hours'),
      completedCount: sql<number>`COUNT(CASE WHEN ${pmSchedule.status} = 'COMPLETED' THEN 1 END)::integer`.as('completed_count'),
      lockedCount: sql<number>`COUNT(CASE WHEN ${pmSchedule.isLocked} = true THEN 1 END)::integer`.as('locked_count'),
    })
    .from(pmSchedule)
    .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
    .innerJoin(fleets, eq(trains.fleetId, fleets.id))
    .where(and(...conditions))
    .groupBy(
      trains.id,
      trains.trainNumber,
      trains.fleetId,
      fleets.code,
      sql`EXTRACT(YEAR FROM ${pmSchedule.targetDate})`
    )
    .orderBy(trains.trainNumber, sql`year`);

  const trainMap = new Map<string, {
    trainId: string;
    trainNumber: string;
    fleetCode: string;
    years: Array<{
      year: number;
      pmCount: number;
      totalHours: number;
      completedCount: number;
      lockedCount: number;
    }>;
  }>();

  let maxPmCount = 0;
  let maxHours = 0;

  for (const row of results) {
    const hours = parseFloat(row.totalHours) || 0;
    maxPmCount = Math.max(maxPmCount, row.pmCount);
    maxHours = Math.max(maxHours, hours);

    if (!trainMap.has(row.trainId)) {
      trainMap.set(row.trainId, {
        trainId: row.trainId,
        trainNumber: row.trainNumber,
        fleetCode: row.fleetCode,
        years: [],
      });
    }

    trainMap.get(row.trainId)!.years.push({
      year: row.year,
      pmCount: row.pmCount,
      totalHours: Math.round(hours * 10) / 10,
      completedCount: row.completedCount,
      lockedCount: row.lockedCount,
    });
  }

  return c.json(
    success(
      {
        trains: Array.from(trainMap.values()),
        heatmapData: {
          maxPmCount,
          maxHours: Math.round(maxHours * 10) / 10,
        },
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * GET /canvas/tactical
 *
 * Get tactical-level canvas data with weekly PM blocks.
 * Used for the detailed scheduling view with drag-and-drop PM movement.
 *
 * Query Parameters:
 * - trainIds: Comma-separated train IDs (UUID[], optional - defaults to all)
 * - fromWeek: Start date of first week (ISO date, defaults to today)
 * - toWeek: End date of last week (ISO date, defaults to +12 weeks)
 */
canvasRoutes.get('/canvas/tactical', async (c) => {
  const requestId = getRequestId(c);

  const trainIdsParam = c.req.query('trainIds');
  const fromWeekParam = c.req.query('fromWeek');
  const toWeekParam = c.req.query('toWeek');

  const trainIds = trainIdsParam ? trainIdsParam.split(',').map((id) => id.trim()) : [];

  for (const id of trainIds) {
    if (!isValidUuid(id)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, `Invalid train ID format: ${id}`, requestId),
        400
      );
    }
  }

  const today = new Date();
  const defaultFromWeek = new Date(today);
  defaultFromWeek.setDate(today.getDate() - today.getDay());

  const defaultToWeek = new Date(defaultFromWeek);
  defaultToWeek.setDate(defaultToWeek.getDate() + 12 * 7);

  let fromWeek: Date;
  let toWeek: Date;

  if (fromWeekParam) {
    fromWeek = new Date(fromWeekParam);
    if (isNaN(fromWeek.getTime())) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid fromWeek date format', requestId),
        400
      );
    }
  } else {
    fromWeek = defaultFromWeek;
  }

  if (toWeekParam) {
    toWeek = new Date(toWeekParam);
    if (isNaN(toWeek.getTime())) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid toWeek date format', requestId),
        400
      );
    }
  } else {
    toWeek = defaultToWeek;
  }

  const fromDate = fromWeek.toISOString().split('T')[0];
  const toDate = toWeek.toISOString().split('T')[0];

  const conditions = [
    gte(pmSchedule.targetDate, fromDate),
    lte(pmSchedule.targetDate, toDate),
    isNull(pmSchedule.scenarioId),
  ];

  if (trainIds.length > 0) {
    conditions.push(inArray(pmSchedule.trainId, trainIds));
  }

  const results = await db
    .select({
      pmId: pmSchedule.id,
      trainId: pmSchedule.trainId,
      trainNumber: trains.trainNumber,
      pmCode: pmTypes.pmCode,
      targetDate: pmSchedule.targetDate,
      status: pmSchedule.status,
      constraintStart: pmSchedule.constraintStart,
      constraintEnd: pmSchedule.constraintEnd,
      isLocked: pmSchedule.isLocked,
      trackNumber: tracks.trackNumber,
      depotCode: depots.code,
      displayColor: pmTypes.displayColor,
      estimatedHours: pmTypes.estimatedHours,
      minTrackDays: pmTypes.minTrackDays,
    })
    .from(pmSchedule)
    .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
    .innerJoin(pmTypes, eq(pmSchedule.pmTypeId, pmTypes.id))
    .leftJoin(tracks, eq(pmSchedule.assignedTrackId, tracks.id))
    .leftJoin(depots, eq(pmSchedule.assignedDepotId, depots.id))
    .where(and(...conditions))
    .orderBy(pmSchedule.targetDate);

  const pmBlocks = results.map((row) => ({
    pmId: row.pmId,
    trainId: row.trainId,
    trainNumber: row.trainNumber,
    pmCode: row.pmCode,
    targetDate: row.targetDate,
    durationDays: row.minTrackDays ?? 1,
    status: row.status,
    constraintStart: row.constraintStart,
    constraintEnd: row.constraintEnd,
    isLocked: row.isLocked ?? false,
    trackNumber: row.trackNumber,
    depotCode: row.depotCode,
    displayColor: row.displayColor ?? '#3B82F6',
    estimatedHours: row.estimatedHours ? parseFloat(row.estimatedHours) : null,
  }));

  const constraintWalls: Array<{
    pmId: string;
    type: 'COMPLIANCE_START' | 'COMPLIANCE_END';
    date: string;
  }> = [];

  for (const pm of results) {
    constraintWalls.push(
      { pmId: pm.pmId, type: 'COMPLIANCE_START', date: pm.constraintStart },
      { pmId: pm.pmId, type: 'COMPLIANCE_END', date: pm.constraintEnd }
    );
  }

  return c.json(
    success(
      {
        pmBlocks,
        constraintWalls,
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * GET /canvas/tactical-wide
 *
 * Get tactical-wide canvas data with monthly PM blocks.
 * Used for the compressed Gantt view bridging strategic and tactical views.
 * Shows 1-year of PM data at monthly granularity.
 *
 * Query Parameters:
 * - trainIds: Comma-separated train IDs (UUID[], optional - defaults to all)
 * - fromDate: Start date (ISO date, defaults to start of current month)
 * - toDate: End date (ISO date, defaults to +12 months)
 *
 * @see specs/006-user-interface.md Section 6.3.1 (Tactical-Wide zoom level 4-8)
 */
canvasRoutes.get('/canvas/tactical-wide', async (c) => {
  const requestId = getRequestId(c);

  const trainIdsParam = c.req.query('trainIds');
  const fromDateParam = c.req.query('fromDate');
  const toDateParam = c.req.query('toDate');

