     1→/**
     2→ * Export Routes
     3→ *
     4→ * REST endpoints for exporting PM schedules (Excel/CSV) and generating reports (PDF).
     5→ * Uses async job processing with status polling.
     6→ *
     7→ * Key endpoints:
     8→ * - POST /export/pm-schedule - Queue PM schedule export
     9→ * - POST /export/report - Queue report generation
    10→ * - GET /export/:jobId - Get export job status and download URL
    11→ * - GET /export/jobs - List export jobs for current user
    12→ *
    13→ * @see specs/005-api.md Section 5.15
    14→ */
    15→
    16→import { Hono } from 'hono';
    17→import {
    18→  success,
    19→  paginatedSuccess,
    20→  error,
    21→  parsePaginationQuery,
    22→  ErrorCodes,
    23→  type AppVariables,
    24→} from '../types';
    25→import { getRequestId, getRequestDuration } from '../middleware/request-context';
    26→import {
    27→  getExportService,
    28→  type PmScheduleExportRequest,
    29→  type ReportExportRequest,
    30→  type ExportJobStatus,
    31→  type ReportType,
    32→} from '../../services/export';
    33→
    34→// Singleton service instance
    35→let exportService: ReturnType<typeof getExportService> | null = null;
    36→
    37→function getService(): ReturnType<typeof getExportService> {
    38→  if (!exportService) {
    39→    exportService = getExportService();
    40→  }
    41→  return exportService;
    42→}
    43→
    44→export const exportRoutes = new Hono<{ Variables: AppVariables }>();
    45→
    46→/**
    47→ * POST /export/pm-schedule
    48→ *
    49→ * Queue a PM schedule export job.
    50→ *
    51→ * Request Body:
    52→ * - format: Export format ('xlsx' or 'csv')
    53→ * - filters: Optional filters (depotId, fleetId, trainId, fromDate, toDate, status, pmTypeId, scenarioId)
    54→ * - columns: Optional list of columns to include
    55→ *
    56→ * Returns 202 Accepted with job ID for polling.
    57→ */
    58→exportRoutes.post('/export/pm-schedule', async (c) => {
    59→  const requestId = getRequestId(c);
    60→  const service = getService();
    61→
    62→  try {
    63→    const body = await c.req.json();
    64→
    65→    // Validate required fields
    66→    if (!body.format) {
    67→      return c.json(
    68→        error(ErrorCodes.VALIDATION_ERROR, 'format is required', requestId, {
    69→          field: 'format',
    70→          expected: ['xlsx', 'csv'],
    71→        }),
    72→        400
    73→      );
    74→    }
    75→
    76→    if (!['xlsx', 'csv'].includes(body.format)) {
    77→      return c.json(
    78→        error(ErrorCodes.VALIDATION_ERROR, 'Invalid format', requestId, {
    79→          field: 'format',
    80→          expected: ['xlsx', 'csv'],
    81→          received: body.format,
    82→        }),
    83→        400
    84→      );
    85→    }
    86→
    87→    // Get user from context (or use default for now)
    88→    const userId = c.get('user')?.id ?? 'system';
    89→
    90→    const request: PmScheduleExportRequest = {
    91→      format: body.format,
    92→      filters: body.filters,
    93→      columns: body.columns,
    94→      requestedBy: userId,
    95→    };
    96→
    97→    const result = await service.queuePmScheduleExport(request);
    98→
    99→    return c.json(
   100→      success(
   101→        {
   102→          jobId: result.jobId,
   103→          status: result.status,
   104→          estimatedSizeBytes: result.estimatedSizeBytes,
   105→        },
   106→        { timing: { durationMs: getRequestDuration(c) } }
   107→      ),
   108→      202
   109→    );
   110→  } catch (err) {
   111→    const message = err instanceof Error ? err.message : 'Failed to queue export';
   112→    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
   113→  }
   114→});
   115→
   116→/**
   117→ * POST /export/report
   118→ *
   119→ * Queue a report generation job.
   120→ *
   121→ * Request Body:
   122→ * - reportType: Type of report to generate
   123→ * - parameters: Report-specific parameters
   124→ *
   125→ * Report Types:
   126→ * - WEEKLY_COMPLIANCE: Weekly PM compliance summary
   127→ * - MONTHLY_SUMMARY: Monthly fleet maintenance summary
   128→ * - FLEET_STATUS: Current fleet status report
   129→ * - DRIFT_REPORT: Baseline drift analysis
