   686→/**
   687→ * GET /integration/conflicts/:id
   688→ *
   689→ * Get details of a specific conflict.
   690→ *
   691→ * @param id - Shadow record ID
   692→ * @returns Conflict details with MMS and Maximo data comparison
   693→ */
   694→integrationRoutes.get('/integration/conflicts/:id', async (c) => {
   695→  const requestId = getRequestId(c);
   696→  const id = c.req.param('id');
   697→
   698→  if (!isValidUuid(id)) {
   699→    return c.json(
   700→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid conflict ID format', requestId),
   701→      400
   702→    );
   703→  }
   704→
   705→  // Using imported db singleton
   706→
   707→  try {
   708→    const shadowRecord = await db.query.maximoShadowRecords.findFirst({
   709→      where: eq(maximoShadowRecords.id, id),
   710→      with: {
   711→        pmScheduleEntry: {
   712→          with: {
   713→            train: true,
   714→            pmType: true,
   715→            assignedDepot: true,
   716→          },
   717→        },
   718→      },
   719→    });
   720→
   721→    if (!shadowRecord) {
   722→      return c.json(
   723→        error(ErrorCodes.NOT_FOUND, 'Conflict not found', requestId),
   724→        404
   725→      );
   726→    }
   727→
   728→    if (shadowRecord.syncStatus !== 'CONFLICT') {
   729→      return c.json(
   730→        error(ErrorCodes.VALIDATION_ERROR, 'Record is not in conflict state', requestId, {
   731→          currentStatus: shadowRecord.syncStatus,
   732→        }),
   733→        400
   734→      );
   735→    }
   736→
   737→    const mmsData = shadowRecord.mmsDataSnapshot as {
   738→      trainId: string;
   739→      pmTypeCode: string;
   740→      targetDate: string;
   741→      status: string;
   742→      assignedDepotId?: string;
   743→      assignedHours?: string;
   744→    } | null;
   745→
   746→    const maximoData = shadowRecord.maximoData as {
   747→      status?: string;
   748→      schedStart?: string;
   749→      schedFinish?: string;
   750→      actualStart?: string;
   751→      actualFinish?: string;
   752→      actualLabor?: number;
   753→      changeDate?: string;
   754→    } | null;
   755→
   756→    return c.json(
   757→      success({
   758→        id: shadowRecord.id,
   759→        pmScheduleId: shadowRecord.pmScheduleId,
   760→        maximoWoNum: shadowRecord.maximoWoNum,
   761→        syncStatus: shadowRecord.syncStatus,
   762→        lastSyncAt: shadowRecord.lastSyncAt?.toISOString() ?? null,
   763→        mmsData: mmsData ? {
   764→          targetDate: mmsData.targetDate,
   765→          status: mmsData.status,
   766→          assignedHours: mmsData.assignedHours,
   767→        } : null,
   768→        maximoData: maximoData ? {
   769→          status: maximoData.status,
