   813→/**
   814→ * Conflict resolution request body
   815→ */
   816→interface ResolveConflictRequest {
   817→  /** Resolution strategy: USE_MMS or USE_MAXIMO */
   818→  resolution: ConflictResolution;
   819→}
   820→
   821→/**
   822→ * POST /integration/conflicts/:id/resolve
   823→ *
   824→ * Resolve a sync conflict.
   825→ *
   826→ * @param id - PM schedule ID (not shadow record ID)
   827→ * @body resolution - Strategy: "USE_MMS" or "USE_MAXIMO"
   828→ *
   829→ * - USE_MMS: Force push MMS data to Maximo (overwrite)
   830→ * - USE_MAXIMO: Apply Maximo data to MMS (accept Maximo's truth)
   831→ */
   832→integrationRoutes.post('/integration/conflicts/:id/resolve', async (c) => {
   833→  const requestId = getRequestId(c);
   834→  const id = c.req.param('id');
   835→  const service = getService();
   836→
   837→  if (!isValidUuid(id)) {
   838→    return c.json(
   839→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid conflict ID format', requestId),
   840→      400
   841→    );
   842→  }
   843→
   844→  let body: ResolveConflictRequest;
   845→
   846→  try {
   847→    body = await c.req.json();
   848→  } catch {
   849→    return c.json(
   850→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid JSON body', requestId),
   851→      400
   852→    );
   853→  }
   854→
   855→  // Validate resolution
   856→  if (!body.resolution || !['USE_MMS', 'USE_MAXIMO'].includes(body.resolution)) {
   857→    return c.json(
   858→      error(
   859→        ErrorCodes.VALIDATION_ERROR,
   860→        'resolution must be "USE_MMS" or "USE_MAXIMO"',
   861→        requestId
   862→      ),
   863→      400
   864→    );
   865→  }
   866→
   867→  // First, check if this is a shadow record ID or PM schedule ID
   868→  // Using imported db singleton
   869→  let pmScheduleId = id;
   870→
   871→  // Try to find shadow record by ID first
   872→  const shadowById = await db.query.maximoShadowRecords.findFirst({
   873→    where: eq(maximoShadowRecords.id, id),
   874→  });
   875→
   876→  if (shadowById) {
   877→    pmScheduleId = shadowById.pmScheduleId;
   878→  }
   879→
   880→  try {
   881→    // Get user ID from context if available (for audit)
   882→    const user = c.get('user');
   883→    const userId = user?.id;
   884→
   885→    await service.resolveConflict(pmScheduleId, body.resolution, userId);
   886→
   887→    logger.info(
   888→      { requestId, pmScheduleId, resolution: body.resolution, userId },
   889→      'Conflict resolved'
   890→    );
   891→
   892→    return c.json(
   893→      success({
   894→        resolved: true,
   895→        pmScheduleId,
   896→        resolution: body.resolution,
   897→        message:
   898→          body.resolution === 'USE_MMS'
   899→            ? 'MMS data pushed to Maximo'
   900→            : 'Maximo data applied to MMS',
   901→      }, { timing: { durationMs: getRequestDuration(c) } })
   902→    );
   903→  } catch (err) {
   904→    if (err instanceof NotFoundError) {
   905→      return c.json(
   906→        error(ErrorCodes.NOT_FOUND, err.message, requestId),
   907→        404
   908→      );
   909→    }
   910→
   911→    if (err instanceof ValidationError) {
   912→      return c.json(
   913→        error(ErrorCodes.VALIDATION_ERROR, err.message, requestId),
   914→        400
   915→      );
   916→    }
   917→
   918→    logger.error({ requestId, pmScheduleId, error: err }, 'Failed to resolve conflict');
   919→    return c.json(
   920→      error(ErrorCodes.INTERNAL_ERROR, 'Failed to resolve conflict', requestId),
   921→      500
   922→    );
   923→  }
   924→});
