/**
 * Conflict resolution request body
 */
interface ResolveConflictRequest {
  /** Resolution strategy: USE_MMS or USE_MAXIMO */
  resolution: ConflictResolution;
}

/**
 * POST /integration/conflicts/:id/resolve
 *
 * Resolve a sync conflict.
 *
 * @param id - PM schedule ID (not shadow record ID)
 * @body resolution - Strategy: "USE_MMS" or "USE_MAXIMO"
 *
 * - USE_MMS: Force push MMS data to Maximo (overwrite)
 * - USE_MAXIMO: Apply Maximo data to MMS (accept Maximo's truth)
 */
integrationRoutes.post('/integration/conflicts/:id/resolve', async (c) => {
  const requestId = getRequestId(c);
  const id = c.req.param('id');
  const service = getService();

  if (!isValidUuid(id)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid conflict ID format', requestId),
      400
    );
  }

  let body: ResolveConflictRequest;

  try {
    body = await c.req.json();
  } catch {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid JSON body', requestId),
      400
    );
  }

  // Validate resolution
  if (!body.resolution || !['USE_MMS', 'USE_MAXIMO'].includes(body.resolution)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        'resolution must be "USE_MMS" or "USE_MAXIMO"',
        requestId
      ),
      400
    );
  }

  // First, check if this is a shadow record ID or PM schedule ID
  // Using imported db singleton
  let pmScheduleId = id;

  // Try to find shadow record by ID first
  const shadowById = await db.query.maximoShadowRecords.findFirst({
    where: eq(maximoShadowRecords.id, id),
  });

  if (shadowById) {
    pmScheduleId = shadowById.pmScheduleId;
  }

  try {
    // Get user ID from context if available (for audit)
    const user = c.get('user');
    const userId = user?.id;

    await service.resolveConflict(pmScheduleId, body.resolution, userId);

    logger.info(
      { requestId, pmScheduleId, resolution: body.resolution, userId },
      'Conflict resolved'
    );

    return c.json(
      success({
        resolved: true,
        pmScheduleId,
        resolution: body.resolution,
        message:
          body.resolution === 'USE_MMS'
            ? 'MMS data pushed to Maximo'
            : 'Maximo data applied to MMS',
      }, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    if (err instanceof NotFoundError) {
      return c.json(
        error(ErrorCodes.NOT_FOUND, err.message, requestId),
        404
      );
    }

    if (err instanceof ValidationError) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, err.message, requestId),
        400
      );
    }

    logger.error({ requestId, pmScheduleId, error: err }, 'Failed to resolve conflict');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Failed to resolve conflict', requestId),
      500
    );
  }
});

