/**
 * POST /integration/validate-edit
 *
 * Validate if a PM can be edited (not locked by Maximo).
 *
 * This should be called before any PM modification operation to check:
 * 1. Maximo status lock (INPRG, COMP, CLOSE, CAN → read-only)
 * 2. Sync conflict (unresolved conflict → must resolve first)
 * 3. Baseline lock (locked in published baseline → needs scenario)
 *
 * @body pmScheduleId - PM schedule ID to validate
 * @returns Validation result with reason if invalid
 */
integrationRoutes.post('/integration/validate-edit', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  let body: { pmScheduleId: string };

  try {
    body = await c.req.json();
  } catch {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid JSON body', requestId),
      400
    );
  }

  if (!body.pmScheduleId || !isValidUuid(body.pmScheduleId)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid or missing pmScheduleId', requestId),
      400
    );
  }

  try {
    const validation = await service.validateEdit(body.pmScheduleId);

    if (!validation.valid) {
      // Return 423 Locked for Maximo status lock
      if (validation.reason === 'MAXIMO_STATUS_LOCK') {
        return c.json(
          error(
            ErrorCodes.MAXIMO_LOCK,
            validation.message ?? 'PM is locked by Maximo',
            requestId,
            {
              reason: validation.reason,
              maximoStatus: validation.maximoStatus,
              maximoWoNum: validation.maximoWoNum,
              suggestion: validation.suggestion,
            }
          ),
          423
        );
      }

      // Return 409 Conflict for sync conflict
      if (validation.reason === 'SYNC_CONFLICT') {
        return c.json(
          error(
            ErrorCodes.CONFLICT,
            validation.message ?? 'Unresolved sync conflict',
            requestId,
            {
              reason: validation.reason,
              suggestion: validation.suggestion,
            }
          ),
          409
        );
      }

      // Return 423 for baseline lock
      if (validation.reason === 'BASELINE_LOCK') {
        return c.json(
          error(
            ErrorCodes.BASELINE_LOCK,
            validation.message ?? 'PM is locked in published baseline',
            requestId,
            {
              reason: validation.reason,
              suggestion: validation.suggestion,
            }
          ),
          423
        );
      }

      // Return 404 for not found
      return c.json(
        error(ErrorCodes.NOT_FOUND, validation.message ?? 'PM not found', requestId),
        404
      );
    }

    return c.json(
      success({
        valid: true,
        pmScheduleId: body.pmScheduleId,
        message: 'PM can be edited',
      }, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Failed to validate edit');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Failed to validate edit', requestId),
      500
    );
  }
});

