/**
 * PUT /integration/polling/config
 *
 * Update polling configuration.
 *
 * @body intervalMinutes - Polling interval in minutes (default: 15)
 * @body webhookTimeoutMinutes - Minutes without webhook before fallback (default: 30)
 * @body gracePeriodMinutes - Minutes to keep polling after webhook recovery (default: 5)
 * @body deduplicationWindowMs - Deduplication window in milliseconds (default: 5000)
 * @query depotId - Optional depot to configure
 */
integrationRoutes.put('/integration/polling/config', async (c) => {
  const requestId = getRequestId(c);
  const depotId = c.req.query('depotId');

  try {
    const body = await c.req.json();

    // Validate input
    const validFields = ['intervalMinutes', 'webhookTimeoutMinutes', 'gracePeriodMinutes', 'deduplicationWindowMs'];
    const config: Record<string, number> = {};

    for (const field of validFields) {
      if (field in body) {
        const value = body[field];
        if (typeof value !== 'number' || value < 1) {
          return c.json(
            error(ErrorCodes.VALIDATION_ERROR, `${field} must be a positive number`, requestId),
            400
          );
        }
        config[field] = value;
      }
    }

    const pollingService = getPollingService();
    await pollingService.updatePollingConfig(config, depotId);

    const updatedConfig = await pollingService.getPollingConfig(depotId);

    logger.info({ requestId, depotId, config }, 'Updated polling configuration');

    return c.json(
      success(updatedConfig, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Failed to update polling config');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Failed to update polling config', requestId),
      500
    );
  }
});

/**
 * POST /integration/polling/activate
 *
 * Manually activate polling fallback mode.
 * Use this when webhooks are known to be unavailable.
 *
 * @query depotId - Optional depot to activate
 *
 * @see specs/007-integration.md Section 7.4.7
 */
integrationRoutes.post('/integration/polling/activate', async (c) => {
  const requestId = getRequestId(c);
  const depotId = c.req.query('depotId');

  try {
    const pollingService = getPollingService();

    await pollingService.activatePolling(depotId, 'manual');

    const health = await pollingService.getWebhookHealth(depotId);

    logger.info({ requestId, depotId }, 'Manually activated polling fallback');

    return c.json(
      success({
        activated: true,
        syncMode: health.syncMode,
        message: 'Polling fallback activated',
      }, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Failed to activate polling');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Failed to activate polling', requestId),
      500
    );
  }
});

/**
 * POST /integration/polling/deactivate
 *
 * Manually deactivate polling fallback mode.
 * Use this when webhooks are restored and working.
 *
 * @query depotId - Optional depot to deactivate
 */
integrationRoutes.post('/integration/polling/deactivate', async (c) => {
  const requestId = getRequestId(c);
  const depotId = c.req.query('depotId');

  try {
    const pollingService = getPollingService();

    await pollingService.deactivatePolling(depotId);

    const health = await pollingService.getWebhookHealth(depotId);

    logger.info({ requestId, depotId }, 'Manually deactivated polling fallback');

    return c.json(
      success({
        deactivated: true,
        syncMode: health.syncMode,
        message: 'Polling fallback deactivated',
      }, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Failed to deactivate polling');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Failed to deactivate polling', requestId),
      500
    );
  }
});

/**
 * POST /integration/polling/execute
 *
 * Manually execute a polling sync operation.
 * Useful for testing or forcing an immediate sync.
 *
 * @query depotId - Optional depot to poll
 */
integrationRoutes.post('/integration/polling/execute', async (c) => {
  const requestId = getRequestId(c);
  const depotId = c.req.query('depotId');

  try {
    const pollingService = getPollingService();

    const result = await pollingService.executePolling(depotId);

    logger.info(
      {
        requestId,
        depotId,
        processed: result.processed,
        updated: result.updated,
        duplicatesPrevented: result.duplicatesPrevented,
      },
      'Executed manual polling sync'
    );

    return c.json(
      success(result, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Failed to execute polling');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Failed to execute polling', requestId),
      500
    );
  }
});

/**
 * POST /integration/polling/check
 *
 * Check webhook health and activate polling if needed.
 * This can be called periodically to ensure failover happens automatically.
 *
 * @query depotId - Optional depot to check
 */
integrationRoutes.post('/integration/polling/check', async (c) => {
  const requestId = getRequestId(c);
  const depotId = c.req.query('depotId');

  try {
    const pollingService = getPollingService();

    const activated = await pollingService.checkAndActivatePollingIfNeeded(depotId);
    const health = await pollingService.getWebhookHealth(depotId);

    return c.json(
      success({
        checked: true,
        pollingActivated: activated,
        syncMode: health.syncMode,
        webhookHealthy: health.isHealthy,
        minutesSinceLastWebhook: health.minutesSinceLastWebhook,
      }, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Failed to check webhook health');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Failed to check webhook health', requestId),
      500
    );
  }
});

