/**
 * MMS WebSocket Hub
 *
 * Manages WebSocket connections for real-time canvas updates, optimizer progress,
 * and collaborative editing. Implements:
 * - Connection management with JWT authentication
 * - Region-based canvas subscriptions
 * - Event broadcasting with room support
 * - PM move via WebSocket with validation
 * - Optimizer progress streaming
 *
 * Security:
 * - All connections must authenticate within 10 seconds
 * - Unauthenticated connections are automatically closed
 * - All events are only sent to authorized users
 *
 * @see specs/005-api.md Section 5.14 (WebSocket Events)
 */

import type { ServerWebSocket } from 'bun';
import { randomUUID } from 'crypto';
import { logger } from '../../lib/logging/logger';
import { getAuthService, type SessionData } from '../../services/auth';
import type {
  ClientConnection,
  CanvasSubscriptionRegion,
  ClientMessage,
  ServerMessage,
  PmUpdatedData,
  PmLockedData,
  ManhourUpdatedData,
  DriftUpdatedData,
  OptimizerProgressData,
  OptimizerCompleteData,
  Room,
} from './types';

// =============================================================================
// Constants
// =============================================================================

const AUTH_TIMEOUT_MS = 10_000;
const PING_INTERVAL_MS = 30_000;
const MAX_SUBSCRIPTIONS_PER_CLIENT = 10;

// =============================================================================
// WebSocket Hub
// =============================================================================

/**
 * Auth service interface for dependency injection
 */
export interface AuthServiceLike {
  verifyAccessToken(token: string): Promise<SessionData>;
}

/**
 * WebSocket Hub for real-time communication
 */
export class WebSocketHub {
  /** Active client connections by connection ID */
  private connections = new Map<string, ClientConnection>();

  /** WebSocket instances by connection ID */
  private sockets = new Map<string, ServerWebSocket<WebSocketData>>();

  /** Rooms for broadcasting */
  private rooms = new Map<string, Room>();

  /** User ID to connection IDs mapping (one user can have multiple connections) */
  private userConnections = new Map<string, Set<string>>();

  /** Auth timeout handles */
  private authTimeouts = new Map<string, ReturnType<typeof setTimeout>>();

  /** Ping interval handle */
  private pingInterval?: ReturnType<typeof setInterval>;

  private log = logger.child({ service: 'websocket-hub' });

  /** Auth service getter - allows injection for testing */
  private authServiceGetter: () => AuthServiceLike;

  constructor(authServiceGetter?: () => AuthServiceLike) {
    this.authServiceGetter = authServiceGetter ?? getAuthService;
    // Create default rooms
    this.createRoom('canvas', 'canvas');
    this.createRoom('optimizer', 'optimizer');
  }

  /**
   * Start the hub (start ping interval)
   */
  start(): void {
    this.pingInterval = setInterval(() => this.broadcastPing(), PING_INTERVAL_MS);
    this.log.info('WebSocket hub started');
  }

  /**
   * Stop the hub (cleanup)
   */
  stop(): void {
    if (this.pingInterval) {
      clearInterval(this.pingInterval);
    }

    // Close all connections
    for (const [connectionId] of this.connections) {
      this.disconnect(connectionId, 'Server shutting down');
    }

    this.log.info('WebSocket hub stopped');
  }

  /**
   * Handle new WebSocket connection
   */
  onOpen(ws: ServerWebSocket<WebSocketData>): void {
    const connectionId = ws.data.connectionId;

    const connection: ClientConnection = {
      id: connectionId,
      state: 'authenticating',
      subscriptions: new Map(),
      connectedAt: new Date(),
      lastActivityAt: new Date(),
      ipAddress: ws.data.ipAddress,
      userAgent: ws.data.userAgent,
    };

    this.connections.set(connectionId, connection);
    this.sockets.set(connectionId, ws);

    // Set auth timeout - client must authenticate within timeout period
    const timeoutHandle = setTimeout(() => {
      const conn = this.connections.get(connectionId);
      if (conn && conn.state !== 'authenticated') {
        this.log.warn({ connectionId }, 'Connection auth timeout - closing');
        this.disconnect(connectionId, 'Authentication timeout');
      }
    }, AUTH_TIMEOUT_MS);

    this.authTimeouts.set(connectionId, timeoutHandle);

    this.log.debug({ connectionId, ipAddress: ws.data.ipAddress }, 'WebSocket connection opened');
  }

  /**
   * Handle WebSocket message
   */
  async onMessage(ws: ServerWebSocket<WebSocketData>, message: string | Buffer): Promise<void> {
    const connectionId = ws.data.connectionId;
    const connection = this.connections.get(connectionId);

    if (!connection) {
      ws.close(4001, 'Connection not found');
      return;
    }

    connection.lastActivityAt = new Date();

    try {
      const data = typeof message === 'string' ? message : message.toString('utf-8');
      const msg = JSON.parse(data) as ClientMessage;

      await this.handleMessage(connectionId, msg);
    } catch (error) {
      this.log.error({ connectionId, error }, 'Error parsing WebSocket message');
      this.sendError(connectionId, 'PARSE_ERROR', 'Invalid message format');
    }
  }

  /**
   * Handle WebSocket close
   */
  onClose(ws: ServerWebSocket<WebSocketData>, code: number, reason: string): void {
    const connectionId = ws.data.connectionId;
    this.cleanup(connectionId);
    this.log.debug({ connectionId, code, reason }, 'WebSocket connection closed');
  }

  /**
   * Handle WebSocket error
   */
  onError(ws: ServerWebSocket<WebSocketData>, error: Error): void {
    const connectionId = ws.data.connectionId;
    this.log.error({ connectionId, error: error.message }, 'WebSocket error');
    this.cleanup(connectionId);
  }

  // ===========================================================================
  // Message Handlers
  // ===========================================================================

  private async handleMessage(connectionId: string, msg: ClientMessage): Promise<void> {
    const connection = this.connections.get(connectionId);
    if (!connection) return;

    switch (msg.type) {
      case 'AUTH':
        await this.handleAuth(connectionId, msg.data.token);
        break;

      case 'canvas:subscribe':
        this.handleSubscribe(connectionId, msg.data);
        break;

      case 'canvas:unsubscribe':
        this.handleUnsubscribe(connectionId, msg.data.subscriptionId);
        break;

      case 'canvas:move_pm':
        await this.handleMovePm(connectionId, msg.data);
        break;

      case 'ping':
        this.send(connectionId, { type: 'pong' });
        break;

      default:
        this.sendError(connectionId, 'UNKNOWN_MESSAGE', `Unknown message type: ${(msg as { type: string }).type}`);
    }
  }

  /**
   * Handle authentication request
   */
  private async handleAuth(connectionId: string, token: string): Promise<void> {
    const connection = this.connections.get(connectionId);
    if (!connection) return;

    try {
      const authService = this.authServiceGetter();
      const session: SessionData = await authService.verifyAccessToken(token);

      // Clear auth timeout
      const timeoutHandle = this.authTimeouts.get(connectionId);
      if (timeoutHandle) {
        clearTimeout(timeoutHandle);
        this.authTimeouts.delete(connectionId);
      }

      // Update connection state
      connection.userId = session.userId;
      connection.displayName = session.email;
      connection.roles = session.roles;
      connection.depotId = session.depotId ?? undefined;
      connection.state = 'authenticated';

      // Track user connection
      let userConns = this.userConnections.get(session.userId);
      if (!userConns) {
        userConns = new Set();
        this.userConnections.set(session.userId, userConns);
      }
      userConns.add(connectionId);

      // Join default rooms (canvas for PM/manhour/drift updates, optimizer for job progress)
      this.joinRoom(connectionId, 'canvas');
      this.joinRoom(connectionId, 'optimizer');

      // Send success response
      this.send(connectionId, {
        type: 'AUTH_RESULT',
        data: {
          success: true,
          userId: session.userId,
          displayName: session.email,
        },
      });

      this.log.info({ connectionId, userId: session.userId }, 'WebSocket authenticated');
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Authentication failed';
      this.send(connectionId, {
        type: 'AUTH_RESULT',
        data: { success: false, error: message },
      });

      // Close connection after failed auth
      this.disconnect(connectionId, 'Authentication failed');
    }
  }

  /**
   * Handle canvas subscription request
   */
  private handleSubscribe(connectionId: string, region: CanvasSubscriptionRegion): void {
    const connection = this.connections.get(connectionId);
    if (!connection || connection.state !== 'authenticated') {
      this.sendError(connectionId, 'UNAUTHORIZED', 'Must be authenticated to subscribe');
      return;
    }

    if (connection.subscriptions.size >= MAX_SUBSCRIPTIONS_PER_CLIENT) {
      this.sendError(connectionId, 'MAX_SUBSCRIPTIONS', `Maximum ${MAX_SUBSCRIPTIONS_PER_CLIENT} subscriptions allowed`);
      return;
    }

    const subscriptionId = randomUUID();
    connection.subscriptions.set(subscriptionId, region);

    // Create room for this subscription if it doesn't exist
    const roomId = this.getCanvasRoomId(region);
    if (!this.rooms.has(roomId)) {
      this.createRoom(roomId, 'canvas', { region });
    }
    this.joinRoom(connectionId, roomId);

    // Count trains in region (simplified - would query DB in production)
    const trainCount = region.trainIds?.length ?? 0;

    this.send(connectionId, {
      type: 'canvas:subscription_confirmed',
      data: {
        subscriptionId,
        region,
        trainCount,
      },
    });

    this.log.debug({ connectionId, subscriptionId, region }, 'Canvas subscription created');
  }

  /**
   * Handle canvas unsubscription request
   */
  private handleUnsubscribe(connectionId: string, subscriptionId: string): void {
    const connection = this.connections.get(connectionId);
    if (!connection) return;

    const region = connection.subscriptions.get(subscriptionId);
    if (region) {
      connection.subscriptions.delete(subscriptionId);

      // Leave the room if this was the only subscription
      const roomId = this.getCanvasRoomId(region);
      this.leaveRoom(connectionId, roomId);
    }
  }

  /**
   * Handle PM move request via WebSocket
   *
   * CRITICAL: Validates against Maximo status lock to prevent race conditions
   * with in-progress work orders.
   */
  private async handleMovePm(connectionId: string, data: { pmId: string; newTargetDate: string; newTrackId?: string }): Promise<void> {
    const connection = this.connections.get(connectionId);
    if (!connection || connection.state !== 'authenticated') {
      this.send(connectionId, {
        type: 'canvas:move_pm_result',
        data: {
          success: false,
          pmId: data.pmId,
          error: { code: 'UNAUTHORIZED', message: 'Must be authenticated' },
        },
      });
      return;
    }

    try {
      // Dynamic import to avoid circular dependency
      const { getPMSchedulerService } = await import('../../services/pm-scheduler');
      const pmService = getPMSchedulerService();

      // Get current PM state for validation and broadcasting
      const pm = await pmService.getPm(data.pmId);
      const previousDate = pm.targetDate;

      // Move the PM (validation happens in the service)
      await pmService.movePm({
        pmScheduleId: data.pmId,
        newTargetDate: data.newTargetDate,
        newTrackId: data.newTrackId,
        reason: 'Moved via drag-and-drop on canvas',
        movedBy: connection.userId!,
      });

      // Send success to requestor
      this.send(connectionId, {
        type: 'canvas:move_pm_result',
        data: {
          success: true,
          pmId: data.pmId,
          newTargetDate: data.newTargetDate,
          newTrackId: data.newTrackId,
        },
      });

      // Broadcast to all canvas subscribers
      this.broadcastPmUpdated({
        pmId: data.pmId,
        trainId: pm.trainId,
        trainNumber: pm.train?.trainNumber ?? 'Unknown',
        changes: [
          { field: 'targetDate', oldValue: previousDate, newValue: data.newTargetDate },
          ...(data.newTrackId ? [{ field: 'assignedTrackId', oldValue: pm.assignedTrackId, newValue: data.newTrackId }] : []),
        ],
        changedBy: {
          userId: connection.userId!,
          displayName: connection.displayName ?? 'Unknown',
        },
      });

      this.log.info({ connectionId, pmId: data.pmId, newTargetDate: data.newTargetDate }, 'PM moved via WebSocket');
    } catch (error) {
      // Map specific error types to WebSocket error codes
      let errorCode: 'MAXIMO_LOCK' | 'OUTSIDE_WINDOW' | 'TRACK_CONFLICT' | 'MATERIAL_BLOCK' | 'BASELINE_LOCK' | 'NOT_FOUND' | 'INTERNAL_ERROR' = 'INTERNAL_ERROR';
      let suggestion: string | undefined;
      let maximoStatus: string | undefined;

      if (error instanceof Error) {
        const errorName = error.constructor.name;

        if (errorName === 'MaximoLockError') {
          errorCode = 'MAXIMO_LOCK';
          suggestion = 'Wait for work order completion or update in Maximo';
          maximoStatus = 'INPRG';
        } else if (errorName === 'ComplianceWindowError') {
          errorCode = 'OUTSIDE_WINDOW';
          suggestion = 'Drag within the highlighted compliance window';
        } else if (errorName === 'TrackConflictError') {
          errorCode = 'TRACK_CONFLICT';
          suggestion = 'Select a different track or date';
        } else if (errorName === 'PmScheduleNotFoundError') {
          errorCode = 'NOT_FOUND';
        } else if (errorName === 'BusinessRuleError' && error.message.includes('locked')) {
          errorCode = 'BASELINE_LOCK';
          suggestion = 'Unlock the PM first or contact the user who locked it';
        }
      }

      const message = error instanceof Error ? error.message : 'Failed to move PM';
      this.send(connectionId, {
        type: 'canvas:move_pm_result',
        data: {
          success: false,
          pmId: data.pmId,
          error: { code: errorCode, message, suggestion, maximoStatus },
        },
      });
      this.log.error({ connectionId, pmId: data.pmId, error }, 'PM move failed');
    }
  }

  // ===========================================================================
  // Broadcasting Methods
  // ===========================================================================

  /**
   * Broadcast PM updated event to all canvas subscribers
   */
  broadcastPmUpdated(data: PmUpdatedData): void {
    this.broadcastToRoom('canvas', {
      type: 'canvas:pm_updated',
      data,
      timestamp: new Date().toISOString(),
    });
  }

  /**
   * Broadcast PM lock/unlock event
   */
  broadcastPmLocked(data: PmLockedData): void {
    this.broadcastToRoom('canvas', {
      type: 'canvas:pm_locked',
      data,
      timestamp: new Date().toISOString(),
    });
  }

  /**
   * Broadcast man-hour updated event
   */
  broadcastManhourUpdated(data: ManhourUpdatedData): void {
    this.broadcastToRoom('canvas', {
      type: 'canvas:manhour_updated',
      data,
      timestamp: new Date().toISOString(),
    });
  }

  /**
   * Broadcast drift analysis updated event
   */
  broadcastDriftUpdated(data: DriftUpdatedData): void {
    this.broadcastToRoom('canvas', {
      type: 'canvas:drift_updated',
      data,
      timestamp: new Date().toISOString(),
    });
  }

  /**
   * Broadcast optimizer progress to optimizer room
   */
  broadcastOptimizerProgress(data: OptimizerProgressData): void {
    this.broadcastToRoom('optimizer', {
      type: 'optimizer:progress',
      data,
      timestamp: new Date().toISOString(),
    });
  }

  /**
   * Broadcast optimizer complete to optimizer room
   */
  broadcastOptimizerComplete(data: OptimizerCompleteData): void {
    this.broadcastToRoom('optimizer', {
      type: 'optimizer:complete',
      data,
      timestamp: new Date().toISOString(),
    });
  }

  /**
   * Broadcast to a specific user (all their connections)
   */
  broadcastToUser(userId: string, message: ServerMessage): void {
    const connectionIds = this.userConnections.get(userId);
    if (connectionIds) {
      for (const connectionId of connectionIds) {
        this.send(connectionId, message);
      }
    }
  }

  // ===========================================================================
  // Room Management
  // ===========================================================================

  private createRoom(roomId: string, type: Room['type'], metadata?: Record<string, unknown>): void {
    if (!this.rooms.has(roomId)) {
      this.rooms.set(roomId, {
        id: roomId,
        type,
        clients: new Set(),
        metadata,
      });
    }
  }

  private joinRoom(connectionId: string, roomId: string): void {
    const room = this.rooms.get(roomId);
    if (room) {
      room.clients.add(connectionId);
    }
  }

  private leaveRoom(connectionId: string, roomId: string): void {
    const room = this.rooms.get(roomId);
    if (room) {
      room.clients.delete(connectionId);
    }
  }

  private broadcastToRoom(roomId: string, message: ServerMessage): void {
    const room = this.rooms.get(roomId);
    if (!room) return;

    for (const connectionId of room.clients) {
      this.send(connectionId, message);
    }
  }

  private getCanvasRoomId(region: CanvasSubscriptionRegion): string {
    // Create a unique room ID based on region
    const parts = [
      `zoom:${region.zoomLevel}`,
      `from:${region.fromDate}`,
      `to:${region.toDate}`,
    ];
    if (region.trainIds?.length) {
      parts.push(`trains:${region.trainIds.slice(0, 5).join(',')}`);
    }
    if (region.depotIds?.length) {
      parts.push(`depots:${region.depotIds.join(',')}`);
    }
    return `canvas:${parts.join('|')}`;
  }

  // ===========================================================================
  // Helper Methods
  // ===========================================================================

  private send(connectionId: string, message: ServerMessage): void {
    const ws = this.sockets.get(connectionId);
    if (ws) {
      try {
        ws.send(JSON.stringify(message));
      } catch (error) {
        this.log.error({ connectionId, error }, 'Failed to send WebSocket message');
        this.cleanup(connectionId);
      }
    }
  }

  private sendError(connectionId: string, code: string, message: string, details?: unknown): void {
    this.send(connectionId, {
      type: 'error',
      data: { code, message, details },
    });
  }

  private disconnect(connectionId: string, reason: string): void {
    const ws = this.sockets.get(connectionId);
    if (ws) {
      try {
        ws.close(1000, reason);
      } catch {
        // Ignore close errors
      }
    }
    this.cleanup(connectionId);
  }

  private cleanup(connectionId: string): void {
    const connection = this.connections.get(connectionId);
    if (connection) {
      // Remove from user connections
      if (connection.userId) {
        const userConns = this.userConnections.get(connection.userId);
        if (userConns) {
          userConns.delete(connectionId);
          if (userConns.size === 0) {
            this.userConnections.delete(connection.userId);
          }
        }
      }

      // Leave all rooms
      for (const room of this.rooms.values()) {
        room.clients.delete(connectionId);
      }
    }

    // Clear auth timeout
    const timeoutHandle = this.authTimeouts.get(connectionId);
    if (timeoutHandle) {
      clearTimeout(timeoutHandle);
      this.authTimeouts.delete(connectionId);
    }

    this.connections.delete(connectionId);
    this.sockets.delete(connectionId);
  }

  private broadcastPing(): void {
    for (const [connectionId, connection] of this.connections) {
      if (connection.state === 'authenticated') {
        this.send(connectionId, { type: 'pong' } as ServerMessage);
      }
    }
  }

  // ===========================================================================
  // Statistics
  // ===========================================================================

  /**
   * Get hub statistics for monitoring
   */
  getStats(): {
    totalConnections: number;
    authenticatedConnections: number;
    uniqueUsers: number;
    rooms: number;
    subscriptions: number;
  } {
    let authenticatedCount = 0;
    let totalSubscriptions = 0;

    for (const connection of this.connections.values()) {
      if (connection.state === 'authenticated') {
        authenticatedCount++;
      }
      totalSubscriptions += connection.subscriptions.size;
    }

    return {
      totalConnections: this.connections.size,
      authenticatedConnections: authenticatedCount,
      uniqueUsers: this.userConnections.size,
      rooms: this.rooms.size,
      subscriptions: totalSubscriptions,
    };
  }

  /**
   * Get connection by ID
   */
  getConnection(connectionId: string): ClientConnection | undefined {
    return this.connections.get(connectionId);
  }

  /**
   * Get all connections for a user
   */
  getUserConnections(userId: string): ClientConnection[] {
    const connectionIds = this.userConnections.get(userId);
    if (!connectionIds) return [];

    const connections: ClientConnection[] = [];
    for (const connectionId of connectionIds) {
      const conn = this.connections.get(connectionId);
      if (conn) {
        connections.push(conn);
      }
    }
    return connections;
  }
}

// =============================================================================
// WebSocket Data Interface (for Bun)
// =============================================================================

export interface WebSocketData {
  connectionId: string;
  ipAddress?: string;
  userAgent?: string;
}

// =============================================================================
// Singleton Instance
// =============================================================================

let hubInstance: WebSocketHub | null = null;

/**
 * Get the singleton WebSocketHub instance
 */
export function getWebSocketHub(): WebSocketHub {
  if (!hubInstance) {
    hubInstance = new WebSocketHub();
  }
  return hubInstance;
}

/**
 * Create a new connection ID
 */
export function createConnectionId(): string {
  return randomUUID();
}

