   348→  const created = await service.schedulePm(request);
   349→
   350→  return c.json(
   351→    success({
   352→      id: created.id,
   353→      trainId: created.trainId,
   354→      pmTypeId: created.pmTypeId,
   355→      targetDate: created.targetDate,
   356→      targetMileageKm: created.targetMileageKm,
