   421→/**
   422→ * GET /scenarios/:id/changes
   423→ *
   424→ * Get all changes (deltas) applied to a scenario in order.
   425→ */
   426→scenarioRoutes.get('/scenarios/:id/changes', async (c) => {
   427→  const requestId = getRequestId(c);
   428→  const scenarioId = c.req.param('id');
