   440→    deltaType: delta.deltaType,
   441→    entityType: delta.entityType,
   442→    entityId: delta.entityId,
   443→    oldValues: delta.oldValues,
   444→    newValues: delta.newValues,
   445→    changeReason: delta.changeReason,
   446→    createdBy: delta.createdBy,
   447→    createdAt: delta.createdAt,
   448→  }));
   449→
   450→  return c.json(
   451→    success(changes, { timing: { durationMs: getRequestDuration(c) } })
