   459→ */
   460→scenarioRoutes.post('/scenarios/:id/undo', async (c) => {
   461→  const requestId = getRequestId(c);
   462→  const scenarioId = c.req.param('id');
   463→
   464→  if (!isValidUuid(scenarioId)) {
   465→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid scenario ID format', requestId), 400);
   466→  }
   467→
   468→  const userId = c.get('user')?.id ?? 'system';
