   564→          400
   565→        );
   566→      }
   567→      scenarioBId = body.compareTo.id;
   568→    } else if (body.compareTo.type === 'BASELINE' && body.compareTo.id) {
   569→      if (!isValidUuid(body.compareTo.id)) {
   570→        return c.json(
