   572→          400
   573→        );
   574→      }
   575→      baselineId = body.compareTo.id;
   576→    }
   577→  }
   578→
   579→  const service = getService();
   580→  const comparison = await service.compareScenarios(scenarioId, scenarioBId, baselineId);
   581→
   582→  return c.json(
   583→    success(
   584→      {
   585→        comparison: {
