   597→          pmAdded: comparison.pmDifferences.added,
   598→          pmRemoved: comparison.pmDifferences.removed,
   599→          pmMoved: comparison.pmDifferences.moved,
   600→          pmUnchanged: comparison.pmDifferences.unchanged,
   601→          totalHoursDelta: comparison.manhourDifferences.totalDelta,
   602→          totalCostDelta: comparison.costDifferences.totalDelta,
   603→          overloadedWeeksDelta: comparison.manhourDifferences.overloadedWeeksDelta,
   604→        },
   605→        pmDifferences: comparison.pmDifferences.details.map((diff) => ({
   606→          pmId: diff.pmId,
   607→          trainId: diff.trainId,
   608→          trainNumber: diff.trainNumber,
   609→          pmTypeId: diff.pmTypeId,
   610→          pmCode: diff.pmCode,
   611→          changeType: diff.changeType,
   612→          scenarioADate: diff.scenarioADate,
   613→          scenarioBDate: diff.scenarioBDate,
   614→          daysDifference: diff.daysDifference,
   615→        })),
   616→        manhourImpact: {
   617→          scenarioATotalHours: comparison.manhourDifferences.scenarioATotalHours,
   618→          scenarioBTotalHours: comparison.manhourDifferences.scenarioBTotalHours,
   619→          weeklyChanges: comparison.manhourDifferences.details,
   620→        },
   621→        costImpact: {
   622→          scenarioATotalCost: comparison.costDifferences.scenarioATotalCost,
   623→          scenarioBTotalCost: comparison.costDifferences.scenarioBTotalCost,
   624→          laborDelta: comparison.costDifferences.laborDelta,
   625→          materialDelta: comparison.costDifferences.materialDelta,
   626→        },
   627→      },
   628→      { timing: { durationMs: getRequestDuration(c) } }
   629→    )
   630→  );
   631→});
   632→
   633→/**
   634→ * POST /scenarios/:id/promote
   635→ *
   636→ * Promote a scenario to become the new production baseline.
   637→ * This will:
   638→ * 1. Materialize all scenario deltas
   639→ * 2. Create a new published baseline
   640→ * 3. Apply the deltas to the production PM schedule
   641→ * 4. Mark the scenario as PROMOTED
