        })),
        pmCount: materialized.pmSchedule.length,
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * POST /scenarios/:id/compare
 *
 * Compare a scenario to a baseline or another scenario.
 *
 * Request body:
 * - compareTo: Comparison target specification
 *   - type: 'BASELINE' | 'SCENARIO'
 *   - id: Target ID (optional for BASELINE - uses latest published)
 */
scenarioRoutes.post('/scenarios/:id/compare', async (c) => {
  const requestId = getRequestId(c);
  const scenarioId = c.req.param('id');

  if (!isValidUuid(scenarioId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid scenario ID format', requestId), 400);
  }

  const body = await c.req.json();

  // Default to comparing with latest baseline if not specified
  let scenarioBId: string | null = null;
  let baselineId: string | undefined;

  if (body.compareTo) {
    if (body.compareTo.type === 'SCENARIO') {
      if (!body.compareTo.id) {
        return c.json(
          error(ErrorCodes.VALIDATION_ERROR, 'compareTo.id is required for SCENARIO type', requestId),
          400
        );
      }
      if (!isValidUuid(body.compareTo.id)) {
        return c.json(
          error(ErrorCodes.VALIDATION_ERROR, 'Invalid compareTo.id format', requestId),
          400
        );
      }
      scenarioBId = body.compareTo.id;
    } else if (body.compareTo.type === 'BASELINE' && body.compareTo.id) {
      if (!isValidUuid(body.compareTo.id)) {
        return c.json(
          error(ErrorCodes.VALIDATION_ERROR, 'Invalid compareTo.id format', requestId),
          400
        );
      }
      baselineId = body.compareTo.id;
    }
  }

  const service = getService();
  const comparison = await service.compareScenarios(scenarioId, scenarioBId, baselineId);

  return c.json(
    success(
      {
        comparison: {
          comparisonId: comparison.comparisonId,
          scenarioA: comparison.scenarioAId,
          scenarioAName: comparison.scenarioAName,
          scenarioB: comparison.scenarioBId ?? null,
          scenarioBName: comparison.scenarioBName,
          baselineId: comparison.baselineId,
          baselineVersion: comparison.baselineVersion,
          comparisonDate: comparison.comparisonDate,
        },
        summary: {
          pmCountDelta: comparison.pmDifferences.countDelta,
          pmAdded: comparison.pmDifferences.added,
          pmRemoved: comparison.pmDifferences.removed,
          pmMoved: comparison.pmDifferences.moved,
          pmUnchanged: comparison.pmDifferences.unchanged,
          totalHoursDelta: comparison.manhourDifferences.totalDelta,
          totalCostDelta: comparison.costDifferences.totalDelta,
          overloadedWeeksDelta: comparison.manhourDifferences.overloadedWeeksDelta,
        },
        pmDifferences: comparison.pmDifferences.details.map((diff) => ({
          pmId: diff.pmId,
          trainId: diff.trainId,
          trainNumber: diff.trainNumber,
          pmTypeId: diff.pmTypeId,
          pmCode: diff.pmCode,
          changeType: diff.changeType,
          scenarioADate: diff.scenarioADate,
          scenarioBDate: diff.scenarioBDate,
          daysDifference: diff.daysDifference,
        })),
        manhourImpact: {
          scenarioATotalHours: comparison.manhourDifferences.scenarioATotalHours,
          scenarioBTotalHours: comparison.manhourDifferences.scenarioBTotalHours,
          weeklyChanges: comparison.manhourDifferences.details,
        },
        costImpact: {
          scenarioATotalCost: comparison.costDifferences.scenarioATotalCost,
          scenarioBTotalCost: comparison.costDifferences.scenarioBTotalCost,
          laborDelta: comparison.costDifferences.laborDelta,
          materialDelta: comparison.costDifferences.materialDelta,
        },
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * POST /scenarios/:id/promote
 *
 * Promote a scenario to become the new production baseline.
 * This will:
 * 1. Materialize all scenario deltas
 * 2. Create a new published baseline
 * 3. Apply the deltas to the production PM schedule
 * 4. Mark the scenario as PROMOTED
 * 5. Supersede any previous published baseline
 *
 * Request body:
 * - baselineName: Name for the new baseline (required)
 * - description: Optional description
 */
scenarioRoutes.post('/scenarios/:id/promote', async (c) => {
  const requestId = getRequestId(c);
  const scenarioId = c.req.param('id');

  if (!isValidUuid(scenarioId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid scenario ID format', requestId), 400);
  }

  const body = await c.req.json();

  // Validate required fields
  if (!body.baselineName || typeof body.baselineName !== 'string' || body.baselineName.trim().length === 0) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'baselineName is required', requestId),
      400
    );
  }

  const userId = c.get('user')?.id ?? 'system';

  const service = getService();
  const baseline = await service.promoteToBaseline({
    scenarioId,
    baselineName: body.baselineName.trim(),
    baselineDescription: body.description?.trim(),
    userId,
  });

  return c.json(
    success(
      {
        promoted: true,
        scenarioId,
        baseline: {
          id: baseline.id,
          name: baseline.name,
          version: baseline.version,
          baselineDate: baseline.baselineDate,
          status: baseline.status,
          publishedAt: baseline.publishedAt,
        },
      },
      { timing: { durationMs: getRequestDuration(c) } }
    ),
    201
  );
});

/**
 * POST /scenarios/cleanup
 *
 * Manually trigger cleanup of expired scenarios.
 * Normally this runs as a scheduled job.
 */
scenarioRoutes.post('/scenarios/cleanup', async (c) => {
  const service = getService();
  const expiredCount = await service.cleanupExpiredScenarios();

  return c.json(
    success(
      { cleaned: true, expiredCount },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

