   615→/**
   616→ * GET /canvas/manhour-overlay
   617→ *
   618→ * Get man-hour overlay data showing depot workload by week.
   619→ * Used to visualize resource utilization in the canvas sidebar.
   620→ *
   621→ * Query Parameters:
   622→ * - depotId: Filter by depot (UUID, optional)
   623→ * - weeks: Number of weeks to include (default: 12)
   624→ */
   625→canvasRoutes.get('/canvas/manhour-overlay', async (c) => {
   626→  const requestId = getRequestId(c);
   627→  
   628→  const depotIdParam = c.req.query('depotId');
   629→  const weeksParam = c.req.query('weeks');
   630→
   631→  if (depotIdParam && !isValidUuid(depotIdParam)) {
   632→    return c.json(
   633→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid depot ID format', requestId),
   634→      400
   635→    );
   636→  }
   637→
   638→  const numWeeks = weeksParam ? parseInt(weeksParam, 10) : 12;
   639→  if (isNaN(numWeeks) || numWeeks < 1 || numWeeks > 52) {
   640→    return c.json(
   641→      error(ErrorCodes.VALIDATION_ERROR, 'Weeks must be between 1 and 52', requestId),
   642→      400
   643→    );
   644→  }
   645→
   646→  const latestRunResult = await db
   647→    .select({ projectionRunId: manhourProjections.projectionRunId })
   648→    .from(manhourProjections)
   649→    .orderBy(desc(manhourProjections.createdAt))
   650→    .limit(1);
   651→
   652→  if (latestRunResult.length === 0) {
   653→    return c.json(
   654→      success(
   655→        { weeks: [] },
   656→        { timing: { durationMs: getRequestDuration(c) } }
   657→      )
   658→    );
   659→  }
   660→
   661→  const latestRunId = latestRunResult[0].projectionRunId;
   662→
   663→  const conditions = [
   664→    eq(manhourProjections.projectionRunId, latestRunId),
   665→    eq(manhourProjections.granularity, 'WEEKLY'),
   666→  ];
   667→
   668→  if (depotIdParam) {
   669→    conditions.push(eq(manhourProjections.depotId, depotIdParam));
   670→  }
   671→
   672→  const projections = await db
   673→    .select({
   674→      projectionId: manhourProjections.id,
   675→      depotId: manhourProjections.depotId,
   676→      depotCode: depots.code,
   677→      periodStart: manhourProjections.periodStart,
   678→      periodEnd: manhourProjections.periodEnd,
   679→      requiredHours: manhourProjections.requiredTotalHours,
   680→      availableHours: manhourProjections.availableTotalHours,
   681→    })
   682→    .from(manhourProjections)
   683→    .innerJoin(depots, eq(manhourProjections.depotId, depots.id))
   684→    .where(and(...conditions))
   685→    .orderBy(manhourProjections.periodStart, depots.code)
   686→    .limit(numWeeks * 10);
   687→
   688→  const adjustmentsResult = await db
   689→    .select({
   690→      projectionId: manhourAdjustments.projectionId,
   691→      adjustmentType: manhourAdjustments.adjustmentType,
   692→      hoursAdjusted: manhourAdjustments.hoursAdjusted,
   693→      status: manhourAdjustments.status,
   694→    })
   695→    .from(manhourAdjustments)
   696→    .where(
   697→      and(
   698→        inArray(
   699→          manhourAdjustments.projectionId,
   700→          projections.map((p) => p.projectionId)
   701→        ),
   702→        eq(manhourAdjustments.status, 'PROPOSED')
   703→      )
   704→    );
   705→
   706→  const adjustmentsByProjection = new Map<string, typeof adjustmentsResult>();
   707→  for (const adj of adjustmentsResult) {
   708→    if (!adjustmentsByProjection.has(adj.projectionId)) {
   709→      adjustmentsByProjection.set(adj.projectionId, []);
   710→    }
   711→    adjustmentsByProjection.get(adj.projectionId)!.push(adj);
   712→  }
   713→
   714→  const weekMap = new Map<string, {
   715→    weekStart: string;
   716→    depots: Array<{
   717→      depotId: string;
   718→      depotCode: string;
   719→      requiredHours: number;
   720→      availableHours: number;
   721→      utilizationPct: number;
   722→      status: 'OVERLOADED' | 'OPTIMAL' | 'UNDERUTILIZED';
   723→      adjustments: Array<{
   724→        type: string;
   725→        hours: number;
   726→        status: string;
   727→      }>;
   728→    }>;
   729→  }>();
   730→
   731→  for (const proj of projections) {
   732→    const weekStart = proj.periodStart;
   733→    const required = parseFloat(proj.requiredHours);
   734→    const available = parseFloat(proj.availableHours);
   735→    const utilizationPct = available > 0 ? (required / available) * 100 : 0;
   736→
   737→    let status: 'OVERLOADED' | 'OPTIMAL' | 'UNDERUTILIZED';
   738→    if (required > available) {
   739→      status = 'OVERLOADED';
   740→    } else if (utilizationPct < 70) {
   741→      status = 'UNDERUTILIZED';
   742→    } else {
   743→      status = 'OPTIMAL';
   744→    }
   745→
   746→    const adjustments = (adjustmentsByProjection.get(proj.projectionId) || []).map((a) => ({
   747→      type: a.adjustmentType,
   748→      hours: parseFloat(a.hoursAdjusted),
   749→      status: a.status ?? 'PROPOSED',
   750→    }));
   751→
   752→    if (!weekMap.has(weekStart)) {
   753→      weekMap.set(weekStart, { weekStart, depots: [] });
   754→    }
   755→
   756→    weekMap.get(weekStart)!.depots.push({
   757→      depotId: proj.depotId,
   758→      depotCode: proj.depotCode,
   759→      requiredHours: Math.round(required * 10) / 10,
   760→      availableHours: Math.round(available * 10) / 10,
   761→      utilizationPct: Math.round(utilizationPct * 10) / 10,
   762→      status,
   763→      adjustments,
   764→    });
   765→  }
   766→
   767→  const weeks = Array.from(weekMap.values()).sort(
   768→    (a, b) => a.weekStart.localeCompare(b.weekStart)
   769→  );
   770→
   771→  return c.json(
   772→    success(
   773→      { weeks },
   774→      { timing: { durationMs: getRequestDuration(c) } }
   775→    )
   776→  );
   777→});
