   957→        message: `Compliance window closes in ${daysToDeadline} days`,
   958→      });
   959→    }
   960→
   961→    return {
   962→      pmId: row.pmId,
   963→      trainId: row.trainId,
   964→      trainNumber: row.trainNumber,
   965→      fleetCode: row.fleetCode,
   966→      pmCode: row.pmCode,
   967→      pmDescription: row.pmName ?? row.pmCode,
   968→      targetDate: row.targetDate,
   969→      endDate: endDate.toISOString().split('T')[0],
   970→      durationDays,
   971→      status: row.status,
   972→      constraintStart: row.constraintStart,
   973→      constraintEnd: row.constraintEnd,
   974→      isLocked: row.isLocked ?? false,
   975→      trackNumber: row.trackNumber,
   976→      depotCode: row.depotCode,
   977→      estimatedHours: row.estimatedHours ? parseFloat(row.estimatedHours) : null,
   978→      assignedShift: row.assignedShift,
   979→      // Material requirements - empty for now, can be populated from inventory integration
   980→      materials: [] as Array<{
