  1086→        },
  1087→        { timing: { durationMs: getRequestDuration(c) } }
  1088→      )
  1089→    );
  1090→  }
  1091→
  1092→  const latestDate = latestAnalysisResult[0].analysisDate;
  1093→
  1094→  const driftResults = await db
  1095→    .select({
  1096→      trainId: driftAnalysis.trainId,
