  1104→    })
  1105→    .from(driftAnalysis)
  1106→    .innerJoin(trains, eq(driftAnalysis.trainId, trains.id))
  1107→    .where(
  1108→      and(
  1109→        eq(driftAnalysis.baselineId, baseline.id),
  1110→        eq(driftAnalysis.analysisDate, latestDate)
  1111→      )
  1112→    )
  1113→    .orderBy(trains.trainNumber);
  1114→
  1115→  const thresholds = {
  1116→    mileageDriftPct: 5.0,
  1117→    scheduleDriftDays: 14,
